var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아주 먼 옛날, 한 명의 구도자가 있었다.","JPN":"はるか昔、一人の求道者がいた。","ENG":"Once upon a time, there lived a seeker of truth.","TWN":"很久很久以前，有一位求道者。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그는 세상을 떠돌며 수많은 사람을 구하고, 그들의 고통을 대신 끌어안았다.","JPN":"彼は世界を周りながら多くの人々を救い、彼らの苦痛を代わりに抱え込んだ。","ENG":"The Seeker traveled the world, saving many lives, bearing their suffering on their behalf.","TWN":"他走遍世界拯救許多的人，替他們承擔痛苦。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"많은 이들이 구도자를 칭송했고, 그와 함께 고행의 길을 걷고자 했다.","JPN":"多くの人が求道者を称え、彼と共に苦行の道を歩もうとした。","ENG":"Many praised the Seeker and followed him in his path of righteous suffering.","TWN":"求道者因此受到人們的愛戴，並且開始與他一起踏上修行之路。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 고통은 끝나지 않았다.","JPN":"しかし、苦痛は消えなかった。","ENG":"But the suffering would never end.","TWN":"但痛苦沒有結束。"},"stage":{"bg":"MAINSTREAM_7010010","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"전쟁과 병마. 기아와 재난. 핍박과 착취.","JPN":"戦争と病魔。飢餓と災禍。逼迫と搾取。","ENG":"With war and pestilence... famine and disasters... the oppression and the exploitation of the weak...","TWN":"戰爭與兵戎，飢餓與天災，強取與豪奪。"},"stage":{"bg":"MAINSTREAM_7010010","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":null,"text":{"KOREA":"어디를 가도 그들을 둘러싼 것은 고통이었다.","JPN":"どこへ行っても彼らを取り巻くのは苦痛だった。","ENG":"There was no end to suffering, no matter where they went.","TWN":"無論去到哪裡，等待他們的就只有痛苦。"},"stage":{"bg":"MAINSTREAM_7010010","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"구도자는 시들어 갔고, 그를 따르던 이들도 하나씩 떠나갔다.","JPN":"求道者は衰えていき、彼を慕っていた人々も一人ずつ去っていった。","ENG":"The Seeker withered away, and his followers left him one by one.","TWN":"求道者越來越軟弱，原本跟隨著他的人們也一個一個離開。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"많은 이들이 구도자를 비웃었고, 그의 지친 뒷모습을 손가락질했다.","JPN":"多くの人が求道者を嘲笑し、彼の疲れ果てた後ろ姿に指を差した。","ENG":"Many ridiculed the Seeker, mocking his weary mien.","TWN":"人們開始嘲諷求道者，在他軟弱的背後指指點點。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"홀로 남은 구도자는, 묵묵히 세상의 끝으로 떠났다.","JPN":"独り残された求道者は、黙々と世界の果てへと旅立った。","ENG":"Alone again, the Seeker quietly set off to the edge of the world.","TWN":"孤單一人的求道者於是默默地走向世界的盡頭。"},"stage":{"bg":"MAINSTREAM_7010011","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그곳에서 그는 세상의 모든 지식을 알고 있다는 현자와 마주했다.","JPN":"そこで彼は、この世すべての知識を得たという賢者に出会った。","ENG":"There, he met a sage said to possess all the world's knowledge.","TWN":"在那個地方，求道者遇到一位無所不知的智者。"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"구도자는 현자에게 청했다.","JPN":"求道者は賢者に願った。","ENG":"The Seeker pled with the sage.","TWN":"求道者於是向智者請教。"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>위대한 용이 될 방법을 알고 싶소.</color>","JPN":"<color=#ffd34c>偉大なる龍になる方法が知りたい。</color>","ENG":"<color=#ffd34c> I would like to know how to become a great dragon.</color>","TWN":"<color=#ffd34c>我想知道，有什麼方法可以成為偉大的龍。</color>"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"현자는 어째서 용이 되길 원하는지 물었다.","JPN":"賢者はなぜ龍になりたいのか尋ねた。","ENG":"The sage asked the Seeker why.","TWN":"智者問：你為何想成為龍？"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"침묵하던 구도자는 이윽고 고통스러운 표정으로 대답했다.","JPN":"沈黙していた求道者は、やがて苦しそうな表情で答えた。","ENG":"After a brief silence, the Seeker responded with an agonized look on his face.","TWN":"求道者沉默片刻後以痛苦的表情作為回答。"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"세상은 슬픔과 비극이 멈추지 않는 곳이었다.","JPN":"この世は悲しみと悲劇が止まらないところだった。","ENG":"The world as he knew it was full of grief and tragedy.","TWN":"世界是一個充滿痛苦和悲劇的地方。"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"그런 세상을 바꾸고자 그는 세상의 모든 고통을 대신 짊어지려 했다.","JPN":"そんな世界を変えようと、彼はこの世すべての苦痛を代わりに背負おうとした。","ENG":"He sought to bear the suffering of everyone, in order to change the world.","TWN":"他想要透過承擔世人的痛苦來改變世界。"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 모든 것이 끝난 지금, 결국 그는 아무것도 바꾸지 못했다.","JPN":"しかし、すべてが終わった今、結局彼は何も変えられなかった。","ENG":"But now that the endeavor had come to an end, he realized he hadn't changed a thing.","TWN":"結果到頭來卻什麼也沒改變。"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"남은 것은 오직 고통뿐.","JPN":"残ったのは苦痛だけ。","ENG":"The only thing that remained was suffering.","TWN":"留下來的就只有痛苦而已。"},"stage":{"bg":"MAINSTREAM_7010012","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};